mapper.insert:
		/*
             SQL ID : QbnkQstnVwitmDAO.qbnkQstnVwitmBulkRegist
             설  명 : 문제은행문항보기항목일괄등록
         */
         INSERT ALL

			INTO TB_LMS_QBNK_QSTN_VWITM (
	         	  QBNK_QSTN_VWITM_ID
				, QBNK_QSTN_ID
				, VWITM_CTS
				, VWITM_SEQNO
				, CRANSYN
				, RGTR_ID
				, REG_DTTM
	         ) VALUES (
	         	  #{item.qbnkQstnVwitmId}
				, #{item.qbnkQstnId}
				, #{item.vwitmCts}
				, #{item.vwitmSeqno}
				, #{item.cransyn}
				, #{item.rgtrId}
				, FN_DTTM()
	         )

		SELECT * FROM DUAL

mapper.delete:
		/*
             SQL ID : QbnkQstnVwitmDAO.qbnkQstnVwitmDelete
             설  명 : 문제은행문항보기항목삭제
         */
         DELETE FROM TB_LMS_QBNK_QSTN_VWITM
          WHERE QBNK_QSTN_ID = #{qbnkQstnId}
